import torch
import torch_npu
import custom_ops_lib

_FN = "max_pooling_1d_custom"

class ModelNew(torch.nn.Module):
    def __init__(self, kernel_size: int, stride: int = None, padding: int = 0, return_indices: bool = False):
        super(ModelNew, self).__init__()
        self.kernel_size = int(kernel_size)
        self.stride = self.kernel_size if (stride is None or stride <= 0) else int(stride)
        self.padding = int(padding)
        self.return_indices = bool(return_indices)

    def forward(self, x: torch.Tensor):
        fn = getattr(custom_ops_lib, _FN)
        # return_indices is not supported; ignored (assumed False)
        return fn(x, int(self.kernel_size), int(self.stride), int(self.padding))
